package com.document.editor
import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.provider.OpenableColumns
import android.view.*
import android.widget.TextView
import android.widget.Toast
import androidx.activity.result.contract.ActivityResultContracts
import androidx.fragment.app.Fragment
import androidx.lifecycle.lifecycleScope
import androidx.navigation.fragment.findNavController
import androidx.recyclerview.widget.LinearLayoutManager
import androidx.recyclerview.widget.RecyclerView
import com.google.android.material.floatingactionbutton.FloatingActionButton
import kotlinx.coroutines.flow.first
import kotlinx.coroutines.launch
class DocumentListFragment : Fragment() {
    private lateinit var recyclerView: RecyclerView
    private lateinit var fab: FloatingActionButton
    private lateinit var repository: RecentFilesRepository
    private val pickDocumentLauncher = registerForActivityResult(ActivityResultContracts.OpenDocument()) { uri: Uri? ->
        uri?.let {
            try {
                requireContext().contentResolver.takePersistableUriPermission(
                    it,
                    Intent.FLAG_GRANT_READ_URI_PERMISSION or Intent.FLAG_GRANT_WRITE_URI_PERMISSION
                )
                lifecycleScope.launch {
                    repository.addRecentFile(it.toString())
                }
                openEditor(it)
            } catch (e: Exception) {
                Toast.makeText(requireContext(), "Failed to open file: ${e.message}", Toast.LENGTH_SHORT).show()
            }
        }
    }
    override fun onCreateView(
        inflater: LayoutInflater, container: ViewGroup?, savedInstanceState: Bundle?
    ): View? {
        return inflater.inflate(R.layout.fragment_document_list, container, false)
    }
    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)
        repository = RecentFilesRepository(requireContext())
        recyclerView = view.findViewById(R.id.recyclerView)
        fab = view.findViewById(R.id.fab)
        val adapter = RecentFilesAdapter { uriString ->
            val uri = Uri.parse(uriString)
            if (isFileAccessible(uri)) {
                openEditor(uri)
            } else {
                Toast.makeText(requireContext(), "File is no longer accessible", Toast.LENGTH_SHORT).show()
                lifecycleScope.launch {
                    repository.removeRecentFile(uriString)
                }
            }
        }
        recyclerView.layoutManager = LinearLayoutManager(requireContext())
        recyclerView.adapter = adapter
        lifecycleScope.launch {
            repository.recentFilesFlow.collect { files ->
                adapter.submitList(files.reversed())
            }
        }
        fab.setOnClickListener {
            // Pick a document: support text and pdf, for mvp just allow all or specifically text/pdf/images
            pickDocumentLauncher.launch(arrayOf("*/*"))
        }
    }
    private fun isFileAccessible(uri: Uri): Boolean {
        return try {
            val cursor = requireContext().contentResolver.query(uri, null, null, null, null)
            val isValid = cursor != null && cursor.moveToFirst()
            cursor?.close()
            isValid
        } catch (e: Exception) {
            false
        }
    }
    private fun openEditor(uri: Uri) {
        val bundle = Bundle().apply {
            putString("document_uri", uri.toString())
        }
        findNavController().navigate(R.id.action_list_to_editor, bundle)
    }
}
class RecentFilesAdapter(private val onClick: (String) -> Unit) : RecyclerView.Adapter<RecentFilesAdapter.ViewHolder>() {
    private var items = listOf<String>()
    fun submitList(newItems: List<String>) {
        items = newItems
        notifyDataSetChanged()
    }
    override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): ViewHolder {
        val view = LayoutInflater.from(parent.context).inflate(R.layout.item_recent_file, parent, false)
        return ViewHolder(view, onClick)
    }
    override fun onBindViewHolder(holder: ViewHolder, position: Int) {
        holder.bind(items[position])
    }
    override fun getItemCount() = items.size
    class ViewHolder(view: View, val onClick: (String) -> Unit) : RecyclerView.ViewHolder(view) {
        private val fileName: TextView = view.findViewById(R.id.fileName)
        fun bind(uriString: String) {
            val uri = Uri.parse(uriString)
            fileName.text = uri.lastPathSegment ?: uriString
            itemView.setOnClickListener { onClick(uriString) }
        }
    }
}

